14	
15	type AuthHandler struct {
16		authService *service.AuthService
17		auditStore  *store.AuditStore
18	}
19	
20	func NewAuthHandler(as *service.AuthService, audit *store.AuditStore) *AuthHandler {
21		return &AuthHandler{authService: as, auditStore: audit}
22	}
23	
24	func (h *AuthHandler) Login(c echo.Context) error {
25		var req dto.LoginRequest
26		if err := bindAndValidate(c, &req); err != nil {
27			return err
28		}
29	
30		resp, cookies, err := h.authService.Login(c.Request().Context(), req, c.RealIP())
31		if err != nil {
32			if h.auditStore != nil {
33				h.auditStore.LogEvent(c.Request().Context(), nil, model.AuditActionLoginFailed, "session", nil,
34					map[string]interface{}{"username": req.Username}, c.RealIP())
35			}
36			return mapError(c, err)
37		}
38	
39		for _, cookie := range cookies {
40			c.SetCookie(cookie)
41		}
42	
43		if h.auditStore != nil {
44			uid := resp.User.ID
45			h.auditStore.LogEvent(c.Request().Context(), &uid, model.AuditActionLogin, "session", nil,
46				map[string]interface{}{"username": req.Username}, c.RealIP())
47		}
48		return c.JSON(http.StatusOK, resp)
49	}
50	
51	func (h *AuthHandler) Refresh(c echo.Context) error {
52		cookie, err := c.Cookie("refresh_token")
53		if err != nil {
54			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "missing refresh token")
55		}
56	
57		cookies, err := h.authService.Refresh(c.Request().Context(), cookie.Value)
58		if err != nil {
59			return mapError(c, err)
60		}
61	
62		for _, cookie := range cookies {
63			c.SetCookie(cookie)
64		}
65	
66		if h.auditStore != nil {
67			if uid, parseErr := uuid.Parse(middleware.GetUserID(c)); parseErr == nil {
68				h.auditStore.LogEvent(c.Request().Context(), &uid, model.AuditActionTokenRefresh, "session", nil, nil, c.RealIP())
69			}
70		}
71		return c.JSON(http.StatusOK, map[string]string{"status": "ok"})
72	}
73	
74	func (h *AuthHandler) Me(c echo.Context) error {
75		userID, err := uuid.Parse(middleware.GetUserID(c))
76		if err != nil {
77			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
78		}
79	
80		resp, err := h.authService.GetCurrentUser(c.Request().Context(), userID)
81		if err != nil {
82			return mapError(c, err)
83		}
84		return c.JSON(http.StatusOK, resp)
85	}
86	
87	func (h *AuthHandler) Logout(c echo.Context) error {
88		userID, err := uuid.Parse(middleware.GetUserID(c))
89		if err != nil {
90			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
91		}
92	
93		cookies := h.authService.Logout(c.Request().Context(), userID)
94		for _, cookie := range cookies {
95			c.SetCookie(cookie)
96		}
97	
98		if h.auditStore != nil {
99			h.auditStore.LogEvent(c.Request().Context(), &userID, model.AuditActionLogout, "session", nil, nil, c.RealIP())
100		}
101		return c.JSON(http.StatusOK, map[string]string{"status": "ok"})
102	}
103	
