104	func (h *OrderHandler) Cancel(c echo.Context) error {
105		id, err := uuid.Parse(c.Param("id"))
106		if err != nil {
107			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
108		}
109	
110		var req dto.CancelOrderRequest
111		if err := bindAndValidate(c, &req); err != nil {
112			return err
113		}
114	
115		actorID, err := uuid.Parse(middleware.GetUserID(c))
116		if err != nil {
117			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
118		}
119	
120		order, err := h.orderService.TransitionStatus(c.Request().Context(), id, model.OrderStatusCancelled, actorID, req.Reason)
121		if err != nil {
122			return mapError(c, err)
123		}
124		if h.auditStore != nil {
125			h.auditStore.LogEvent(c.Request().Context(), &actorID, model.AuditActionOrderTransit, "order", &id,
126				map[string]interface{}{"to_status": "cancelled", "reason": req.Reason}, c.RealIP())
127		}
128		return c.JSON(http.StatusOK, order)
129	}
