207	func (h *OrderHandler) transition(c echo.Context, status model.OrderStatus) error {
208		id, err := uuid.Parse(c.Param("id"))
209		if err != nil {
210			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
211		}
212	
213		actorID, err := uuid.Parse(middleware.GetUserID(c))
214		if err != nil {
215			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
216		}
217	
218		order, err := h.orderService.TransitionStatus(c.Request().Context(), id, status, actorID, "")
219		if err != nil {
220			return mapError(c, err)
221		}
222		if h.auditStore != nil {
223			h.auditStore.LogEvent(c.Request().Context(), &actorID, model.AuditActionOrderTransit, "order", &id,
224				map[string]interface{}{"to_status": string(status)}, c.RealIP())
225		}
226		return c.JSON(http.StatusOK, order)
227	}
