25	func (h *MessageHandler) List(c echo.Context) error {
26		orderID, err := uuid.Parse(c.Param("orderId"))
27		if err != nil {
28			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
29		}
30	
31		userID, err := uuid.Parse(middleware.GetUserID(c))
32		if err != nil {
33			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
34		}
35	
36		page, pageSize := pagination(c)
37		messages, total, err := h.messageService.ListByOrder(c.Request().Context(), orderID, userID, page, pageSize)
