12	)
13	
14	type RateLimiterConfig struct {
15		Rate  rate.Limit
16		Burst int
17		KeyFn func(c echo.Context) string
18	}
19	
20	type rateLimiterEntry struct {
21		limiter  *rate.Limiter
22		lastSeen time.Time
23	}
24	
25	type RateLimiter struct {
26		mu       sync.Mutex
27		limiters map[string]*rateLimiterEntry
28		config   RateLimiterConfig
29	}
30	
31	func NewRateLimiter(cfg RateLimiterConfig) *RateLimiter {
32		rl := &RateLimiter{
33			limiters: make(map[string]*rateLimiterEntry),
34			config:   cfg,
35		}
36		go rl.cleanup()
37		return rl
38	}
39	
40	func (rl *RateLimiter) getLimiter(key string) *rate.Limiter {
41		rl.mu.Lock()
42		defer rl.mu.Unlock()
43	
44		e, ok := rl.limiters[key]
45		if !ok {
46			limiter := rate.NewLimiter(rl.config.Rate, rl.config.Burst)
47			rl.limiters[key] = &rateLimiterEntry{limiter: limiter, lastSeen: time.Now()}
48			return limiter
49		}
50		e.lastSeen = time.Now()
51		return e.limiter
52	}
53	
54	func (rl *RateLimiter) cleanup() {
55		ticker := time.NewTicker(10 * time.Minute)
56		defer ticker.Stop()
57		for range ticker.C {
58			rl.mu.Lock()
59			cutoff := time.Now().Add(-1 * time.Hour)
60			for k, e := range rl.limiters {
61				if e.lastSeen.Before(cutoff) {
62					delete(rl.limiters, k)
63				}
64			}
65			rl.mu.Unlock()
66		}
67	}
68	
69	func (rl *RateLimiter) Middleware() echo.MiddlewareFunc {
70		return func(next echo.HandlerFunc) echo.HandlerFunc {
71			return func(c echo.Context) error {
72				// Skip rate limiting if disabled (e.g., during tests)
73				if os.Getenv("DISABLE_RATE_LIMIT") == "true" {
74					return next(c)
75				}
76	
77				key := rl.config.KeyFn(c)
78				limiter := rl.getLimiter(key)
79	
80				if !limiter.Allow() {
81					c.Response().Header().Set("Retry-After", "60")
82					return echo.NewHTTPError(http.StatusTooManyRequests, dto.ErrorResponse{
83						Error: dto.ErrorDetail{
84							Code:      dto.CodeRateLimited,
85							Message:   "too many requests",
86							RequestID: GetRequestID(c),
87						},
88					})
89				}
90				return next(c)
91			}
92		}
93	}
