76	// GetByID returns a collectible. Hidden collectibles are only visible to admin/compliance roles.
77	func (s *CollectibleService) GetByID(ctx context.Context, id uuid.UUID, viewerRoles []string) (*model.Collectible, error) {
78		cacheKey := "collectible:" + id.String()
79		if cached, ok := s.cache.Get(cacheKey); ok {
80			c := cached.(*model.Collectible)
81			if c.Status == "hidden" && !hasAdminOrCompliance(viewerRoles) {
82				return nil, dto.ErrNotFound
83			}
84			return c, nil
85		}
86	
87		c, err := s.collectibleStore.GetByID(ctx, id)
88		if err != nil {
89			return nil, err
90		}
91		if c == nil {
92			return nil, dto.ErrNotFound
93		}
94	
95		// Hidden collectibles only visible to admin/compliance
96		if c.Status == "hidden" && !hasAdminOrCompliance(viewerRoles) {
97			return nil, dto.ErrNotFound
98		}
99	
100		s.cache.Set(cacheKey, c, 2*time.Minute)
101	
102		// Emit item_view event and increment view count async
103		go func() {
104			_ = s.collectibleStore.IncrementViewCount(context.Background(), id)
105		}()
106	
107		return c, nil
108	}
