110	// EmitViewEvent emits an analytics event for viewing. Called separately to have access to userID.
111	func (s *CollectibleService) EmitViewEvent(ctx context.Context, userID *uuid.UUID, collectibleID uuid.UUID) {
112		if s.analyticsStore == nil {
113			return
114		}
115		abVariant := resolveABVariant(s.analyticsStore, userID)
116		go func() {
117			_ = s.analyticsStore.RecordEvent(context.Background(), &model.AnalyticsEvent{
118				UserID:        userID,
119				EventType:     "item_view",
120				CollectibleID: &collectibleID,
121				SessionID:     "server",
122				ABVariant:     abVariant,
123			})
124		}()
125	}
126	
127	// List returns collectibles. Non-admin users can only see published.
128	func (s *CollectibleService) List(ctx context.Context, status string, page, pageSize int, viewerRoles []string, userID *uuid.UUID) ([]model.Collectible, int, error) {
129		// Non-admin/compliance users can ONLY see published
130		if !hasAdminOrCompliance(viewerRoles) {
131			status = "published"
132		}
133	
134		cacheKey := fmt.Sprintf("collectibles:%s:%d:%d", status, page, pageSize)
135		if cached, ok := s.cache.Get(cacheKey); ok {
136			result := cached.(*cachedList)
137			return result.items, result.total, nil
138		}
139	
140		items, total, err := s.collectibleStore.List(ctx, status, page, pageSize)
141		if err != nil {
142			return nil, 0, err
143		}
144	
145		s.cache.Set(cacheKey, &cachedList{items: items, total: total}, 30*time.Second)
146	
147		// Emit catalog_view event async with A/B variant tagging
148		if s.analyticsStore != nil {
149			abVariant := resolveABVariant(s.analyticsStore, userID)
150			go func() {
151				_ = s.analyticsStore.RecordEvent(context.Background(), &model.AnalyticsEvent{
152					UserID:    userID,
153					EventType: "catalog_view",
154					SessionID: "server",
155					ABVariant: abVariant,
156				})
157			}()
158		}
159	
160		return items, total, nil
161	}
