172	func (s *CollectibleService) Update(ctx context.Context, id uuid.UUID, req dto.UpdateCollectibleRequest, actorID uuid.UUID) (*model.Collectible, error) {
173		c, err := s.collectibleStore.GetByID(ctx, id)
174		if err != nil {
175			return nil, err
176		}
177		if c == nil {
178			return nil, dto.ErrNotFound
179		}
180		if c.SellerID != actorID {
181			return nil, dto.ErrForbidden
182		}
183	
184		if req.Title != nil {
185			c.Title = *req.Title
186		}
187		if req.Description != nil {
188			c.Description = *req.Description
189		}
190		if req.PriceCents != nil {
191			c.PriceCents = *req.PriceCents
192		}
193		if req.ImageURL != nil {
194			c.ImageURL = *req.ImageURL
195		}
196		if req.MetadataURI != nil {
197			c.MetadataURI = *req.MetadataURI
198		}
199	
200		if err := s.collectibleStore.Update(ctx, c); err != nil {
201			return nil, fmt.Errorf("update collectible: %w", err)
202		}
203		s.invalidateCache()
204		return c, nil
205	}
