210			return err
211		}
212		if c == nil {
213			return dto.ErrNotFound
214		}
215		if err := s.collectibleStore.Hide(ctx, id, adminID, reason); err != nil {
216			return err
217		}
218		s.invalidateCache()
219		return nil
220	}
