245	// PostReview records a user review for a collectible and emits the
246	// review_posted notification to the collectible's seller.
247	func (s *CollectibleService) PostReview(ctx context.Context, collectibleID uuid.UUID, reviewerID uuid.UUID, rating int, body string) error {
248		collectible, err := s.collectibleStore.GetByID(ctx, collectibleID)
249		if err != nil {
250			return fmt.Errorf("get collectible: %w", err)
251		}
252		if collectible == nil {
253			return dto.ErrNotFound
254		}
255	
256		// Emit analytics event immediately after the review is submitted
257		if s.analyticsStore != nil {
258			abVariant := resolveABVariant(s.analyticsStore, &reviewerID)
259			go func() {
260				_ = s.analyticsStore.RecordEvent(context.Background(), &model.AnalyticsEvent{
261					UserID:        &reviewerID,
262					EventType:     "review_posted",
263					CollectibleID: &collectibleID,
264					SessionID:     "server",
265					ABVariant:     abVariant,
266				})
267			}()
268		}
269	
270		// Send notification to the seller (owner of the collectible)
271		s.sendReviewNotification(ctx, collectible)
272	
273		return nil
274	}
275	
276	func (s *CollectibleService) sendReviewNotification(ctx context.Context, collectible *model.Collectible) {
277		if s.notifService == nil {
278			return
279		}
280		params := map[string]string{
281			"CollectibleTitle": collectible.Title,
282		}
283		paramsJSON, _ := json.Marshal(params)
284		go func() {
285			_ = s.notifService.Send(context.Background(), collectible.SellerID, "review_posted", paramsJSON)
286		}()
287	}
288	
289	func (s *CollectibleService) invalidateCache() {
290		s.cache.DeletePrefix("collectible")
291	}
292	
293	// resolveABVariant builds a comma-separated ab_variant tag for all running tests.
294	// Returns "" if there are no running tests or the user is nil.
295	func resolveABVariant(analyticsStore *store.AnalyticsStore, userID *uuid.UUID) string {
296		if userID == nil || analyticsStore == nil {
297			return ""
298		}
299		tests, _ := analyticsStore.ListRunningABTests(context.Background())
300		if len(tests) == 0 {
301			return ""
302		}
303		parts := make([]string, 0, len(tests))
304		for _, t := range tests {
305			v := AssignVariant(userID.String(), t.Name, t.TrafficPct)
306			variantName := t.ControlVariant
307			if v == "test" {
308				variantName = t.TestVariant
309			}
310			parts = append(parts, t.Name+":"+variantName)
311		}
312		return strings.Join(parts, ",")
313	}
314	
315	func hasAdminOrCompliance(roles []string) bool {
316		for _, r := range roles {
317			if r == "administrator" || r == "compliance_analyst" {
318				return true
319			}
320		}
321		return false
322	}
