285	func (s *OrderService) sendOrderNotification(ctx context.Context, order *model.Order, status model.OrderStatus, reason string) {
286		if s.notifService == nil {
287			return
288		}
289	
290		slugMap := map[model.OrderStatus]string{
291			model.OrderStatusConfirmed:  "order_confirmed",
292			model.OrderStatusProcessing: "order_processing",
293			model.OrderStatusCompleted:  "order_completed",
294			model.OrderStatusCancelled:  "order_cancelled",
295		}
296	
297		slug, ok := slugMap[status]
298		if !ok {
299			return
300		}
301	
302		params := map[string]string{
303			"OrderID": order.ID.String(),
304			"Reason":  reason,
305		}
306		paramsJSON, _ := json.Marshal(params)
