5	func TestIsStatusOnlySlug(t *testing.T) {
6		statusSlugs := []string{
7			"order_confirmed",
8			"order_processing",
9			"order_completed",
10			"order_cancelled",
11			"refund_approved",
12		}
13		for _, slug := range statusSlugs {
14			if !IsStatusOnlySlug(slug) {
15				t.Errorf("expected %q to be a status-only slug", slug)
16			}
17		}
18	
19		auxiliarySlugs := []string{
20			"review_posted",
21			"arbitration_opened",
22			"some_unknown_event",
23		}
24		for _, slug := range auxiliarySlugs {
25			if IsStatusOnlySlug(slug) {
26				t.Errorf("expected %q to NOT be a status-only slug", slug)
27			}
28		}
29	}
