31	func TestStatusOnlyMode_FiltersAuxiliaryEvents(t *testing.T) {
32		// Verify the filtering logic: status_only mode should include status slugs
33		// and exclude auxiliary slugs. This tests the same map used by Send().
34		tests := []struct {
35			slug    string
36			mode    string
37			allowed bool
38		}{
39			// all_events mode allows everything
40			{"order_confirmed", "all_events", true},
41			{"review_posted", "all_events", true},
42			{"arbitration_opened", "all_events", true},
43	
44			// status_only mode filters auxiliary events
45			{"order_confirmed", "status_only", true},
46			{"order_processing", "status_only", true},
47			{"order_completed", "status_only", true},
48			{"order_cancelled", "status_only", true},
49			{"refund_approved", "status_only", true},
50			{"review_posted", "status_only", false},
51			{"arbitration_opened", "status_only", false},
52	
53			// empty mode (backward compat) defaults to all_events behavior
54			{"review_posted", "", true},
55			{"order_confirmed", "", true},
56		}
57	
58		for _, tc := range tests {
59			mode := tc.mode
60			if mode == "" {
61				mode = "all_events"
62			}
63			allowed := mode != "status_only" || statusOnlySlugs[tc.slug]
64			if allowed != tc.allowed {
65				t.Errorf("mode=%q slug=%q: got allowed=%v, want %v", tc.mode, tc.slug, allowed, tc.allowed)
66			}
67		}
68	}
69	
70	func TestDefaultSubscriptionMode(t *testing.T) {
71		// Verify that an empty subscription mode defaults to all_events.
72		// This ensures backward compatibility for users who haven't chosen a mode.
73		mode := ""
74		if mode == "" {
75			mode = "all_events"
76		}
77		if mode != "all_events" {
78			t.Errorf("expected default mode to be all_events, got %q", mode)
79		}
80	}
